using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Preserve "Discriminator" property name (EF Core 9 defaults to "$type").
            // Keeps existing documents and raw SQL like
            //   SELECT * FROM c WHERE c.Discriminator = 'Blog'
            // working without migration.
            b.HasDiscriminator<string>("Discriminator");

            // Preserve id format "Blog|1" (EF Core 9 drops the discriminator prefix).
            b.HasDiscriminatorInJsonId();

            // HasIndex removed — Cosmos manages indexing at the container level
            // and EF Core 9 now throws if HasIndex is called.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

